const body = $input.first().json;
const url = (body.url || body.link || '').trim();
if (!url) throw new Error('No URL provided. Send {"url": "YOUR_LINK"}');

let platform = 'unknown';
let priority = 3;

// Priority 1 — Lossless native (FLAC guaranteed)
if      (url.includes('tidal.com'))   { platform = 'tidal';      priority = 1; }
else if (url.includes('qobuz.com'))   { platform = 'qobuz';      priority = 1; }
// Priority 2 — FLAC available via Lucida
else if (url.includes('deezer.com'))  { platform = 'deezer';     priority = 2; }
// Priority 3 — Converted (Lucida cross-platform fetch)
else if (url.includes('spotify.com')) { platform = 'spotify';    priority = 3; }
else if (url.includes('soundcloud'))  { platform = 'soundcloud'; priority = 3; }
else if (url.includes('apple'))       { platform = 'apple';      priority = 3; }

return [{ json: { url, platform, priority, quality: 'FLAC', ts: new Date().toISOString() } }];
